mapper.select:
SELECT DISTINCT SP.TBL_SO_P_ID AS TBL_RESTOCK_WAIT_ID, SP.TBL_SO_M_ID, SM.SO_NO, DBO.F_COL_NM('A', 'COMM', 'SO_ORDR_TYPE', SM.SO_TYPE) AS SO_TYPE_NM, DBO.F_COL_NM('A', 'COMM', 'SO_STAT_CD', SM.SO_STAT_CD) AS SO_STAT_CD_NM, SP.PROD_CD, SP.PROD_NM, SP.QTY AS RETURN_QTY, ISNULL(SP.RESTOCK_INBOUNDED, 'N') AS INBOUND_YN, SP.RESTOCK_INBOUND_DT AS INBOUND_DT, SP.RESTOCK_INBOUND_USER AS INBOUND_USER, AG.AGNT_NM, SM.ACPT_ER, SM.ACPT_TEL1, SM.POST_CD, SM.ADDR1, DC.DC_NM, SM.DLVY_CNFM_DT, SM.REF_SO_NO, SM.DLVY_RQST_MSG, SM.CUST_SPCL_TXT, SM.SAVE_TIME, UM.USER_NM AS INST_ER, SM.DC_CD, SM.AGNT_CD FROM TBL_SO_P SP INNER JOIN TBL_SO_M SM ON SP.TBL_SO_M_ID = SM.TBL_SO_M_ID LEFT JOIN TBL_MTRL_M PM ON SP.PROD_CD = PM.MTRL_CD AND SM.AGNT_CD = PM.AGNT_CD LEFT JOIN TBL_AGENCY_M AG ON SM.AGNT_CD = AG.AGNT_CD LEFT JOIN TBL_LGST_DC_M DC ON SM.DC_CD = DC.DC_CD LEFT JOIN TBL_INST_PLAN_M IP ON SM.TBL_SO_M_ID = IP.TBL_SO_M_ID LEFT JOIN TBL_USER_M UM ON IP.TBL_USER_M_ID = UM.TBL_USER_M_ID WHERE 1=1 AND SP.USE_YN = 'Y' AND ( (SM.SO_TYPE = '9904' AND SM.SO_STAT_CD NOT IN ('0000', '1900')) OR SM.SO_STAT_CD = '8050' ) AND (AG.AGNT_NM IS NULL OR PATINDEX('%[가-힣]%', AG.AGNT_NM) > 0) -- 한글이 포함된 화주사명만 조회 AND (PM.EXCHANGE_RETURN_EXCLUDE_YN IS NULL OR PM.EXCHANGE_RETURN_EXCLUDE_YN = 'N') AND SM.DLVY_CNFM_DT >= '20251002' -- 배송확정일 기준 2025-10-02 이전 데이터 검색 불가
AND SM.ORDR_INPT_DT >= #{fromDt}
AND SM.ORDR_INPT_DT >= #{fromDt}
AND SM.DLVY_CNFM_DT >= #{fromDt}
AND SM.ORDR_INPT_DT >= #{fromDt}
AND SM.ORDR_INPT_DT <= #{toDt}
AND SM.ORDR_INPT_DT <= #{toDt}
AND SM.DLVY_CNFM_DT <= #{toDt}
AND SM.ORDR_INPT_DT <= #{toDt}
AND SM.AGNT_CD IN
#{agnt}
AND SM.DC_CD IN
#{dc}
AND SM.SO_NO IN
#{so}
AND SM.SO_TYPE IN
#{soType}
AND SM.ACPT_ER LIKE '%' + #{acptNm} + '%'
AND (SM.ACPT_TEL1 LIKE '%' + #{acptTel} + '%' OR SM.ACPT_TEL2 LIKE '%' + #{acptTel} + '%')
AND SP.PROD_CD IN
#{prod}
AND SP.PROD_NM LIKE '%' + #{prodNmSrch} + '%'
AND (SM.ADDR1 LIKE '%' + #{srchAddr} + '%' OR SM.ADDR2 LIKE '%' + #{srchAddr} + '%')
AND ISNULL(SP.RESTOCK_INBOUNDED, 'N') = #{inboundStatus}
AND SM.SO_STAT_CD = #{soStatCd}
ORDER BY SM.SAVE_TIME DESC

mapper.update:
UPDATE TBL_SO_P SET RESTOCK_INBOUNDED = 'N', RESTOCK_INBOUND_DT = NULL, RESTOCK_INBOUND_USER = NULL, RESTOCK_INBOUND_TIME = NULL, UPDT_USER = #{processUser}, UPDT_TIME = GETDATE() WHERE TBL_SO_P_ID IN
#{id}
AND RESTOCK_INBOUNDED = 'Y' -- 입고완료된 것만 되돌리기

UPDATE TBL_MTRL_M
SET CURRENT_QUANTITY = ISNULL(CURRENT_QUANTITY, 0) + CAST(#{returnQty} AS INT),
    UPDT_TIME = GETDATE(),
    UPDT_USER = #{processUser}
WHERE CMPY_CD = 'A'
AND AGNT_CD = #{agntCd}
AND MTRL_CD = #{prodCd}
AND MTO_YN = 'N'

UPDATE TBL_MTRL_M
SET CURRENT_QUANTITY = ISNULL(CURRENT_QUANTITY, 0) - CAST(#{returnQty} AS INT),
    UPDT_TIME = GETDATE(),
    UPDT_USER = #{processUser}
WHERE CMPY_CD = 'A'
AND AGNT_CD = #{agntCd}
AND MTRL_CD = #{prodCd}
AND MTO_YN = 'N'
